/*
 * ISA-101 Operational State CSS
 * Applied as class on the symbol instance's <g> wrapper element.
 * Targets .io-stateful elements within the shape SVG.
 *
 * Gray for normal (#808080) — color only for abnormal operational states.
 * These classes are mutually exclusive; only one should be active at a time.
 */

/* ── RUNNING ─────────────────────────────────────────────── */
/* Green fill/stroke — equipment is energised and operating */
.io-running .io-stateful {
  stroke: #047857 !important; /* emerald-700 */
  fill: none !important;
}
/* Circle-based shapes (pumps, motors, compressors) get a subtle green fill */
.io-running .io-stateful circle {
  fill: rgba(5, 150, 105, 0.15) !important; /* emerald-600 @ 15% */
  stroke: #047857 !important;
}

/* ── STOPPED ─────────────────────────────────────────────── */
/* No override — gray is "stopped/normal" per ISA-101 */
.io-stopped .io-stateful {
  stroke: #808080 !important;
  fill: none !important;
}

/* ── FAULT ───────────────────────────────────────────────── */
/* Red — equipment fault (not an alarm, a physical state) */
.io-fault .io-stateful {
  stroke: #dc2626 !important; /* red-600 */
  fill: none !important;
}
.io-fault .io-stateful circle {
  fill: rgba(220, 38, 38, 0.12) !important;
  stroke: #dc2626 !important;
}

/* ── TRANSITIONING ───────────────────────────────────────── */
/* Amber — starting up or shutting down */
.io-transitioning .io-stateful {
  stroke: #d97706 !important; /* amber-600 */
  fill: none !important;
}

@keyframes io-state-transitioning-pulse {
  0%,
  100% {
    opacity: 1;
  }
  50% {
    opacity: 0.5;
  }
}
.io-transitioning .io-stateful {
  animation: io-state-transitioning-pulse 1.5s ease-in-out infinite;
}

/* ── OUT OF SERVICE ──────────────────────────────────────── */
/* Dashed stroke + hatch fill — equipment is OOS / maintenance */
.io-oos .io-stateful {
  stroke: #808080 !important;
  stroke-dasharray: 4 3 !important;
  fill: url(#io-hatch-pattern) !important;
}
/* Non-SVG fill fallback for environments where pattern refs aren't resolved */
@supports not (fill: url(#io-hatch-pattern)) {
  .io-oos .io-stateful {
    fill: none !important;
  }
}
/*
 * Level-of-Detail (LOD) visibility rules for process graphics
 * (process-implementation-spec.md §4.3.3)
 *
 * The canvas container gets class: io-canvas-container lod-0|1|2|3
 * Each rendered SVG element carries: data-lod="0|1|2|3"
 *
 * LOD 0 (Overview, zoom < 15%)  — major equipment, pipes, large labels
 * LOD 1 (Area,     zoom 15–40%) — + text readouts, alarm indicators, medium labels
 * LOD 2 (Unit,     zoom 40–80%) — + all display elements, fill gauges, sparklines
 * LOD 3 (Detail,   zoom > 80%)  — everything
 *
 * Adjacent tier: opacity transition (smooth fade)
 * Non-adjacent tier: display: none (fully removed from compositing)
 */

/* Default: all elements visible at full LOD */
.io-canvas-container [data-lod] {
  transition: opacity 200ms ease;
}

/* ── LOD 0 (Overview) ─────────────────────────────────────────────────────── */

/* LOD 1 elements: adjacent tier — fade out */
.io-canvas-container.lod-0 [data-lod="1"] {
  opacity: 0;
  pointer-events: none;
  transition: opacity 200ms ease;
}

/* LOD 2 and LOD 3: non-adjacent — fully removed */
.io-canvas-container.lod-0 [data-lod="2"],
.io-canvas-container.lod-0 [data-lod="3"] {
  display: none;
}

/* ── LOD 1 (Area) ─────────────────────────────────────────────────────────── */

/* LOD 2 elements: adjacent tier — fade out */
.io-canvas-container.lod-1 [data-lod="2"] {
  opacity: 0;
  pointer-events: none;
  transition: opacity 200ms ease;
}

/* LOD 3: non-adjacent — fully removed */
.io-canvas-container.lod-1 [data-lod="3"] {
  display: none;
}

/* ── LOD 2 (Unit) ─────────────────────────────────────────────────────────── */

/* LOD 3 elements: adjacent tier — fade out */
.io-canvas-container.lod-2 [data-lod="3"] {
  opacity: 0;
  pointer-events: none;
  transition: opacity 200ms ease;
}

/* ── LOD 3 (Detail) — everything visible ────────────────────────────────── */

.io-canvas-container.lod-3 [data-lod] {
  opacity: 1;
  pointer-events: auto;
  transition: opacity 200ms ease;
}

